import { KernelFunction } from '@semantic-kernel/core';

function validatePlan(plan: any, kernel: Kernel): boolean {
  return plan.steps.every((step: any) => {
    const func = kernel.functions.getFunction(step.plugin, step.function);
    return func !== undefined && 
           step.input?.parameters.every((p: any) => 
             func.describe().inputParameters?.some((ip: any) => ip.name === p.name)
           );
  });
}

// Usage
if (!validatePlan(plan, kernel)) {
  throw new Error('Invalid plan detected - regenerating');
